pure fn direct_parse(text: Text) -> Number {
    return to_number(trim(text))
}
pure fn scan_tokens(text: Text) -> Number {
    for t in split(text, " ") {
        parsed = to_number(t)
        if is_ok(parsed) { return parsed }
    }
    return error("no numeric token found")
}
intent infer_number(text: Text) -> Text {
    goal: the single number in the text or the word unknown
}
entry main(text: Text) {
    return attempt {
        try direct_parse(text)
        try scan_tokens(text)
        try infer_number(text)
    }
}

intent classify_sentiment(text: Text) -> Text {
    goal: positive_or_negative_or_neutral
}
entry main(text: Text) {
    return match classify_sentiment(text) {
        "positive" with confidence > 0.8 => "strong positive",
        "negative" with confidence > 0.8 => "strong negative",
        _ with confidence > 0.6 => "somewhat uncertain",
        _ => "too uncertain to say"
    }
}

pure fn safe_div(a: Number, b: Number) -> Number {
    if b == 0 { return error("divide by zero") }
    return ok(a / b)
}
entry main(x: Text) {
    r = safe_div(10, 2)
    if is_ok(r) { return unwrap(r) }
    return unwrap_error(r)
}

pure fn fib(n: Number) -> Number {
    if n <= 1 { return n }
    return fib(n - 1) + fib(n - 2)
}
entry main(x: Text) { return fib(7) + fib(9) }

pure fn square(n: Number) -> Number { return n * n }
pure fn sum_of_squares(lo: Number, hi: Number) -> Number {
    total = 0
    for i in range(lo, hi + 1) { total = total + square(i) }
    return total
}
entry main(x: Text) { return sum_of_squares(1, 5) }

pure fn fizz_only(n: Number) -> Text {
    picks = []
    for i in range(1, n + 1) {
        if i % 3 == 0 { picks = append(picks, to_text(i)) }
    }
    return join(picks, ",")
}
entry main(x: Text) { return fizz_only(15) }

pure fn dedupe(items: Text) -> Text {
    seen = []
    for it in items {
        if it not in seen { seen = append(seen, it) }
    }
    return seen
}
entry main(x: Text) {
    return join(dedupe(["apple","banana","apple","cherry","banana","date"]), ",")
}

import classify from "stdlib/language"
entry main(text: Text) {
    return classify(text, "positive_negative_or_neutral")
}

intent classify_tone(text: Text) -> Text {
    goal: 문장의 톤을 한국어로 분류
}
pure fn char_count(s: Text) -> Number { return length(s) }
entry main(text: Text) {
    return join([to_text(char_count(text)), "자, ", classify_tone(text)], "")
}

intent translate_to_korean(text: Text) -> Text {
    goal: Korean translation of the source
}
pure fn letter_count(s: Text) -> Number { return length(s) }
entry main(word: Text) {
    return join([to_text(letter_count(word)), " letters - ", translate_to_korean(word)], "")
}

pure fn reverse_text(s: Text) -> Text {
    chars = split(s, "")
    result = ""
    for i in range(0, length(chars)) {
        result = join([result, get(chars, length(chars) - 1 - i)], "")
    }
    return result
}
pure fn is_palindrome(s: Text) -> Boolean {
    return lower(s) == reverse_text(lower(s))
}
entry main(word: Text) {
    if is_palindrome(word) { return "yes" }
    return "no"
}

pure fn reverse_text(s: Text) -> Text {
    chars = split(s, "")
